ci-remove-key.solutionCode:
def remove_item(data, key_name):
    if key_name in data:
        del data[key_name]
    return data

ci-format-items.solutionCode:
def format_inventory(items):
    result = []
    for name, count in items.items():
        result.append(f"{name}: {count}")
    return result

